/**
 * @name HTTP request URI/path flowing to File constructor
 * @description User-controlled HTTP input flows to file system operations
 * @kind path-problem
 * @problem.severity error
 * @id java/http-path-to-file
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module HttpToFileConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // File constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // FileInputStream constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileInputStream") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // FileOutputStream constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileOutputStream") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // Paths.get
    exists(MethodCall mc |
      mc.getMethod().hasName("get") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Paths") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module HttpToFileFlow = TaintTracking::Global<HttpToFileConfig>;
import HttpToFileFlow::PathGraph

from HttpToFileFlow::PathNode source, HttpToFileFlow::PathNode sink
where HttpToFileFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "User-controlled HTTP input $@ flows to file operation.", source.getNode(), "HTTP source"

/**
 * @name Taint flow from HTTP fetchUrl header to URL openStream - SSRF/path traversal via file:// 
 * @description The fetchUrl HTTP header value flows directly to URL.openStream() without scheme validation
 * @kind path-problem
 * @problem.severity error
 * @id java/fetchurl-header-to-url-open
 * @tags security
 *       external/cwe/cwe-073
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module FetchUrlConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // HTTP headers read via JAX-RS HttpHeaders
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("getHeaderString") or
        mc.getMethod().hasName("getFirst") or
        mc.getMethod().hasName("get") or
        mc.getMethod().hasName("getRequestHeader")
      ) and
      source.asExpr() = mc
    )
    or
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // URL.openStream() - opens connection to URL
    exists(MethodCall mc |
      mc.getMethod().hasName("openStream") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.net", "URL") and
      sink.asExpr() = mc.getQualifier()
    )
    or
    // new URL(string) - URL construction from user input  
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.net", "URL") and
      sink.asExpr() = ce.getAnArgument()
    )
  }

  predicate isBarrier(DataFlow::Node node) {
    // If there's a scheme check (contains("://") or startsWith("http"))
    exists(MethodCall mc |
      (mc.getMethod().hasName("startsWith") or mc.getMethod().hasName("contains")) and
      DataFlow::localFlow(node, DataFlow::exprNode(mc.getQualifier()))
    )
  }
}

module FetchUrlFlow = TaintTracking::Global<FetchUrlConfig>;
import FetchUrlFlow::PathGraph

from FetchUrlFlow::PathNode source, FetchUrlFlow::PathNode sink
where FetchUrlFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "HTTP header value flows to URL operation without scheme restriction - potential file:// scheme access to local filesystem."

/**
 * @name Remote flow source directly to URL constructor without scheme restriction
 * @description HTTP request data flows to URL constructor allowing arbitrary URL schemes including file://
 * @kind path-problem
 * @problem.severity error
 * @id java/remote-to-url-constructor
 * @tags security
 *       external/cwe/cwe-073
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module RemoteToUrlConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // new URL(userInput)
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.net", "URL") and
      sink.asExpr() = ce.getAnArgument()
    )
  }

  predicate isBarrier(DataFlow::Node node) {
    // Checks for http/https prefix - scheme restrictions
    exists(MethodCall mc |
      (mc.getMethod().hasName("startsWith") or mc.getMethod().hasName("contains") or mc.getMethod().hasName("matches")) and
      DataFlow::localFlow(node, DataFlow::exprNode(mc.getQualifier()))
    )
  }
}

module RemoteToUrlFlow = TaintTracking::Global<RemoteToUrlConfig>;
import RemoteToUrlFlow::PathGraph

from RemoteToUrlFlow::PathNode source, RemoteToUrlFlow::PathNode sink
where RemoteToUrlFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Remote HTTP input $@ flows to URL constructor without scheme validation - allows file:// or other protocol injection.", source.getNode(), "source"
